	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/auth/logout", wrapper.PostAuthLogout)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/auth/logout/all", wrapper.PostAuthLogoutAll)
