// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Username + password login (proxied through Jellyfin AuthenticateByName)
	// (POST /auth/login)
	PostAuthLogin(ctx context.Context, request PostAuthLoginRequestObject) (PostAuthLoginResponseObject, error)
	// Revoke a refresh token
	// (POST /auth/logout)
	PostAuthLogout(ctx context.Context, request PostAuthLogoutRequestObject) (PostAuthLogoutResponseObject, error)
	// Revoke all refresh tokens for the user
	// (POST /auth/logout/all)
	PostAuthLogoutAll(ctx context.Context, request PostAuthLogoutAllRequestObject) (PostAuthLogoutAllResponseObject, error)
	// Poll Quick Connect approval
	// (POST /auth/quick-connect/poll)
	PostAuthQuickConnectPoll(ctx context.Context, request PostAuthQuickConnectPollRequestObject) (PostAuthQuickConnectPollResponseObject, error)
	// Begin a Jellyfin Quick Connect handshake
	// (POST /auth/quick-connect/start)
	PostAuthQuickConnectStart(ctx context.Context, request PostAuthQuickConnectStartRequestObject) (PostAuthQuickConnectStartResponseObject, error)
	// Refresh token rotation
	// (POST /auth/refresh)
	PostAuthRefresh(ctx context.Context, request PostAuthRefreshRequestObject) (PostAuthRefreshResponseObject, error)
	// Liveness probe
	// (GET /healthz)
	GetHealthz(ctx context.Context, request GetHealthzRequestObject) (GetHealthzResponseObject, error)
	// Home screen sections
	// (GET /home)
	GetHome(ctx context.Context, request GetHomeRequestObject) (GetHomeResponseObject, error)
	// Paginated library browse
	// (GET /library)
	GetLibrary(ctx context.Context, request GetLibraryRequestObject) (GetLibraryResponseObject, error)
	// Item detail with playback handoff
	// (GET /library/{id})
	GetLibraryId(ctx context.Context, request GetLibraryIdRequestObject) (GetLibraryIdResponseObject, error)
	// Episode list for a season
	// (GET /library/{id}/seasons/{seasonNumber}/episodes)
	GetLibraryIdSeasonsSeasonNumberEpisodes(ctx context.Context, request GetLibraryIdSeasonsSeasonNumberEpisodesRequestObject) (GetLibraryIdSeasonsSeasonNumberEpisodesResponseObject, error)
}

type StrictHandlerFunc func(ctx context.Context, w http.ResponseWriter, r *http.Request, request any) (any, error)
type StrictMiddlewareFunc func(f StrictHandlerFunc, operationID string) StrictHandlerFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

// PostAuthLogin operation middleware
func (sh *strictHandler) PostAuthLogin(w http.ResponseWriter, r *http.Request) {
	var request PostAuthLoginRequestObject

	var body PostAuthLoginJSONRequestBody
	if err := json.NewDecoder(r.Body).Decode(&body); err != nil {
		sh.options.RequestErrorHandlerFunc(w, r, fmt.Errorf("can't decode JSON body: %w", err))
		return
	}
	request.Body = &body

	handler := func(ctx context.Context, w http.ResponseWriter, r *http.Request, request interface{}) (interface{}, error) {
		return sh.ssi.PostAuthLogin(ctx, request.(PostAuthLoginRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "PostAuthLogin")
	}

	response, err := handler(r.Context(), w, r, request)

	if err != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, err)
	} else if validResponse, ok := response.(PostAuthLoginResponseObject); ok {
		if err := validResponse.VisitPostAuthLoginResponse(w); err != nil {
			sh.options.ResponseErrorHandlerFunc(w, r, err)
		}
	} else if response != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, fmt.Errorf("unexpected response type: %T", response))
	}
}

